code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Separator, icon } from 'decantr/components';
import { link } from 'decantr/router';

code.example:
function Footer() {
  const { footer, div, h3, span, a, p } = tags;

  const linkGroup = (title, links) =>
    div({ class: css('_flex _col _gap3') },
      h3({ class: css('_textsm _bold _fgfg') }, title),
      ...links.map(l => a({ href: l.href, class: css('_textsm _fgmuted _h:fgfg _nounder _trans[color_0.2s_ease]') }, l.label))
    );

  return footer({ class: css('_bcborder _borderT _mt[auto]') },
    div({ class: css('_grid _gc1 _md:gc4 _gap8 _py12 _px6 _mw[1200px] _mx[auto]') },
      div({ class: css('_flex _col _gap3') },
        span({ class: css('_textlg _bold d-gradient-text') }, 'Decantr'),
        p({ class: css('_textsm _fgmuted _mw[240px]') }, 'The AI-first web framework for building stunning applications.'),
        div({ class: css('_flex _gap3 _mt2') },
          a({ href: '#', 'aria-label': 'GitHub', class: css('_fgmuted _h:fgfg') }, icon('github')),
          a({ href: '#', 'aria-label': 'Twitter', class: css('_fgmuted _h:fgfg') }, icon('twitter'))
        )
      ),
      linkGroup('Product', [
        { label: 'Features', href: '#features' },
        { label: 'Pricing', href: '#pricing' },
        { label: 'Changelog', href: '#changelog' }
      ]),
      linkGroup('Resources', [
        { label: 'Documentation', href: '#docs' },
        { label: 'Examples', href: '#examples' },
        { label: 'Blog', href: '#blog' }
      ]),
      linkGroup('Company', [
        { label: 'About', href: '#about' },
        { label: 'Contact', href: '#contact' },
        { label: 'Privacy', href: '#privacy' }
      ])
    ),
    Separator({}),
    div({ class: css('_flex _aic _jcc _py4 _px6') },
      p({ class: css('_textxs _fgmuted') }, `\u00A9 ${new Date().getFullYear()} Decantr. All rights reserved.`)
    )
  );
}

